const r="/api";function i(t){return fetch(`${r}/routings`,{headers:{Authorization:`Bearer ${t}`}}).then(e=>e.json())}function s(t){return fetch(`${r}/routings/full`,{headers:{Authorization:`Bearer ${t}`}}).then(e=>e.json())}function u(t,e,o){const n=new FormData;return n.append("file",e),n.append("createdBy",o),fetch(`${r}/routings/import`,{method:"POST",headers:{Authorization:`Bearer ${t}`},body:n}).then(a=>a.json())}function h(t,e){const o=new FormData;return o.append("file",e),fetch(`${r}/routings/import/check`,{method:"POST",headers:{Authorization:`Bearer ${t}`},body:o}).then(n=>n.json())}export{s as a,h as c,i as g,u as i};
